    public function run(): void
    {
        /*
         * IMPORTANT:
         * This seeder writes the large JSON columns in separate compact updates.
         * That prevents XAMPP/MySQL from throwing "MySQL server has gone away"
         * when max_allowed_packet is low.
         */
        $now = now();

        DB::table('module_library_items')->updateOrInsert(
            ['module_code' => 'PYTHON-BASIC-V2'],
            [
                'module_no' => 1,
                'title' => 'Basics of Python Programming',
                'year_level' => 'Year 1',
                'version_no' => 2,
                'version_name' => 'Python Practice and MCQ Review',
                'version_code' => 'V2',
                'description' => 'A detailed second version of Python Fundamentals focused on code tracing, debugging, MCQ reasoning, loops, functions, collections, validation, and beginner problem solving.',
                'estimated_minutes' => 480,
                'sort_order' => 2,
                'is_active' => true,
                'created_at' => $now,
                'updated_at' => $now,
            ]
        );

        DB::table('module_library_items')
            ->where('module_code', 'PYTHON-BASIC-V2')
            ->update([
                'content_sections' => json_encode($this->contentSections(), JSON_UNESCAPED_UNICODE),
                'updated_at' => now(),
            ]);

        DB::table('module_library_items')
            ->where('module_code', 'PYTHON-BASIC-V2')
            ->update([
                'mcq_questions' => json_encode($this->mcqQuestions(), JSON_UNESCAPED_UNICODE),
                'updated_at' => now(),
            ]);
    }

